// Merge all data sources into a unified signal array
const emails = $('Gmail – Fetch Unread').all().map(item => ({
  source: 'email',
  id: item.json.id,
  from: item.json.from,
  subject: item.json.subject,
  body: item.json.snippet || item.json.textPlain || '',
  timestamp: item.json.date,
  raw: item.json
}));

const crmContacts = (() => {
  try {
    const res = $('HubSpot – Recent CRM Changes').first().json;
    const results = res.results || [];
    return results.map(c => ({
      source: 'crm',
      id: c.id,
      email: c.properties?.email || '',
      name: `${c.properties?.firstname || ''} ${c.properties?.lastname || ''}`.trim(),
      lifecyclestage: c.properties?.lifecyclestage || '',
      lead_status: c.properties?.hs_lead_status || '',
      timestamp: c.properties?.hs_lastmodifieddate || '',
      raw: c
    }));
  } catch(e) { return []; }
})();

const slackMessages = $('Slack – Fetch Support Channel').all().map(item => ({
  source: 'slack',
  id: item.json.ts,
  user: item.json.user,
  text: item.json.text || '',
  timestamp: item.json.ts,
  raw: item.json
}));

const signals = [...emails, ...crmContacts, ...slackMessages];

if (signals.length === 0) {
  return [{ json: { signals: [], skip: true } }];
}

return [{ json: { signals, skip: false, total: signals.length } }];

// Split signals into individual items for processing
const { signals } = $input.first().json;
return signals.map(s => ({ json: s }));

