// Parse triage output and enrich signal
const signal = $('Split Into Individual Signals').item.json;
let triage = {};

try {
  const content = $input.first().json.message?.content || $input.first().json.choices?.[0]?.message?.content || '{}';
  triage = JSON.parse(content);
} catch(e) {
  triage = {
    urgency: 'medium',
    sentiment: 'neutral',
    intent: 'general_inquiry',
    customer_tier: 'unknown',
    confidence: 0.5,
    summary: 'Could not parse signal',
    recommended_action: 'alert_human',
    reasoning: 'Parse error',
    requires_human: true
  };
}

return [{ json: { ...signal, triage, processedAt: new Date().toISOString() } }];

