// Build task details from signal
const signal = $input.first().json;
const triage = signal.triage;

const priorityMap = {
  critical: 'urgent',
  high: 'high',
  medium: 'normal',
  low: 'low'
};

const taskName = `[${triage.urgency.toUpperCase()}] ${triage.summary}`;
const taskNotes = `Source: ${signal.source}\nIntent: ${triage.intent}\nSentiment: ${triage.sentiment}\nCustomer tier: ${triage.customer_tier}\nConfidence: ${triage.confidence}\nReasoning: ${triage.reasoning}\n\nProcessed at: ${signal.processedAt}`;

return [{ json: { ...signal, task: { name: taskName, notes: taskNotes, priority: priorityMap[triage.urgency] || 'normal' } } }];

// Parse email draft output
const signal = $('Action Router').item.json;
let draft = {};

try {
  const content = $input.first().json.message?.content || $input.first().json.choices?.[0]?.message?.content || '{}';
  draft = JSON.parse(content);
} catch(e) {
  draft = { subject: 'Follow up from our team', body: 'We noticed your recent activity and wanted to reach out.', tone: 'professional' };
}

const autoSend = signal.triage.confidence >= 0.85 && !signal.triage.requires_human;

return [{ json: { ...signal, draft, autoSend } }];

// Parse proposal output
const signal = $('Action Router').item.json;
let proposal = {};

try {
  const content = $input.first().json.message?.content || $input.first().json.choices?.[0]?.message?.content || '{}';
  proposal = JSON.parse(content);
} catch(e) {
  proposal = { subject: 'A proposal from our team', body: 'We have an exciting opportunity for you.', executive_summary: 'Proposal pending.' };
}

const autoSend = signal.triage.confidence >= 0.85 && !signal.triage.requires_human;

return [{ json: { ...signal, proposal, autoSend } }];

