  timestamp: new Date().toISOString(),
  signalId: signal.id || signal.ts || Math.random().toString(36).substr(2,9),
  source: signal.source,
  urgency: signal.triage?.urgency,
  intent: signal.triage?.intent,
  sentiment: signal.triage?.sentiment,
  customer_tier: signal.triage?.customer_tier,
  confidence: signal.triage?.confidence,
  recommended_action: signal.triage?.recommended_action,
  auto_sent: signal.autoSend || false,
  summary: signal.triage?.summary,
  requires_human: signal.triage?.requires_human
};

console.log('AUDIT LOG:', JSON.stringify(logEntry));
return [{ json: logEntry }];
